#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005,mod=998244353;
ll n,m,dep[N],ls[N*32],rs[N*32],tr[N*32],tag[N*32],id[N*32],cnt;//动态开点线段树 数组开大点 总结点数<=nlogn(因为每个update创建<=logn个节点 n个update) 
vector<int> g[N],xianzhi[N];
//tr为线段树所包含的节点的dp之和 
//线段树所包含的节点是l<=dep<=r的节点 （但是是上端点的dep,这也是为什么update,query调用时l=0,r=n,因为上端点dep可能是0） 
void pushup(int u)
{
	tr[u]=(tr[ls[u]]+tr[rs[u]])%mod;
}
void pushdown(int u)
{
	if(tag[u]!=1)
	{
		tr[ls[u]]=tag[u]*tr[ls[u]]%mod;
		tr[rs[u]]=tag[u]*tr[rs[u]]%mod;
		tag[ls[u]]=tag[u]*tag[ls[u]]%mod;
		tag[rs[u]]=tag[u]*tag[rs[u]]%mod;
		tag[u]=1;
	}
}
void update(int l,int r,int pos,ll num,ll  &u)
{
	if(u==0)
	{
		u=++cnt;
		tag[u]=1;
	}
	if(l==r)
	{
		tag[u]=1;
		tr[u]=num;
		return ;
	}
	int mid=(l+r)/2;
	pushdown(u);
	if(pos<=mid) update(l,mid,pos,num,ls[u]);
	else update(mid+1,r,pos,num,rs[u]);
	pushup(u);
}
ll query(int u,int l,int r,int L,int R)
{
	if(L<=l&&R>=r)
	{
		return tr[u];
	}
	int mid=(l+r)/2;
	ll ans=0;
	pushdown(u);
	if(L<=mid) ans=(ans+query(ls[u],l,mid,L,R))%mod;
	if(R>mid) ans=(ans+query(rs[u],mid+1,r,L,R))%mod;
	return ans;
}
ll hebing(int x,int y,int l,int r,ll &sumu,ll &sumv)
{
	if(!x&&!y)
	{
		return 0;
	}
	if(!x)
	{
		sumv=(sumv+tr[y])%mod;
		tag[y]=tag[y]*sumu%mod;
		tr[y]=tr[y]*sumu%mod;
		return y;
	}
	if(!y)
	{
		sumu=(sumu+tr[x])%mod;
		tag[x]=tag[x]*sumv%mod;
		tr[x]=tr[x]*sumv%mod;
		return x;
	}
	if(l==r)
	{
		ll trx=tr[x];
		sumv=(sumv+tr[y])%mod;
		tr[x]=(tr[x]*sumv+tr[y]*sumu)%mod;
		sumu=(sumu+trx)%mod;
		return x;
	}
	ll mid=(l+r)>>1;
	pushdown(x);
	pushdown(y);
	ls[x]=hebing(ls[x],ls[y],l,mid,sumu,sumv);
	rs[x]=hebing(rs[x],rs[y],mid+1,r,sumu,sumv);
	pushup(x);
	return x;
}
void dfs(int u,int f)
{
	dep[u]=dep[f]+1;
	ll mx=0;
	for(int i=0;i<xianzhi[u].size();i++)
	{
		mx=max(mx,dep[xianzhi[u][i]]);
	}
	update(0,n,mx,1,id[u]);
	for(int i=0;i<g[u].size();i++) 
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs(v,u);
		ll tmp1=0,tmp2=query(id[v],0,n,0,dep[u]);
		id[u]=hebing(id[u],id[v],0,n,tmp1,tmp2);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	cin>>m;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		xianzhi[v].push_back(u);
	}
	dfs(1,0);
	cout<<query(id[1],0,n,0,0);
	return 0;
}
